-- Import transformed ETF universe final CSV into public.stock_symbols.
-- Source reflected: reports/Transformed_ETF_Universe_Final.ja.csv
-- Policy: preserve existing trust_fee when already present; overwrite JP name / NISA category from CSV when provided.

-- 0) Ensure destination columns exist
alter table public.stock_symbols
  add column if not exists raw_ticker text,
  add column if not exists isin text,
  add column if not exists asset_type text not null default 'stock',
  add column if not exists country text,
  add column if not exists category text,
  add column if not exists subcategory text,
  add column if not exists benchmark text,
  add column if not exists nisa_category text,
  add column if not exists trust_fee numeric(12,6),
  add column if not exists aum numeric(20,2),
  add column if not exists notes text;

do $$
begin
  alter table public.stock_symbols
    add constraint stock_symbols_asset_type_chk check (asset_type in ('stock', 'fund', 'etf', 'index'));
exception
  when duplicate_object then null;
end $$;

create index if not exists idx_stock_symbols_asset_type on public.stock_symbols (asset_type);
create index if not exists idx_stock_symbols_nisa_category on public.stock_symbols (nisa_category);
create index if not exists idx_stock_symbols_isin on public.stock_symbols (isin);

-- 1) Staging table with the same columns as the final CSV
drop table if exists public.stg_transformed_etf_universe_final;
create table public.stg_transformed_etf_universe_final (
  symbol text,
  raw_ticker text,
  asset_type text,
  jp_name text,
  name_en text,
  isin text,
  exchange text,
  country text,
  category text,
  subcategory text,
  benchmark text,
  nisa_category text,
  trust_fee text,
  aum text,
  currency text,
  is_active text,
  notes text
);

-- 2) Load the CSV rows directly into staging
